import React from 'react'
import { Effect, pipe } from 'https://esm.sh/effect@3'

const program = pipe(
  Effect.succeed(21),
  Effect.map((n) => n * 2),
)

export default function App() {
  const result = Effect.runSync(program)
  return (
    <div className="min-h-screen bg-slate-50 p-8 text-slate-900">
      <h1 className="text-2xl font-bold">Effect basics</h1>
      <p className="mt-2 text-slate-600">An Effect is a description. runSync executes it.</p>
      <p className="mt-4 text-3xl font-bold">result = {result}</p>
    </div>
  )
}

